CREATE OR REPLACE FUNCTION "public"."accept_offer"("p_offer_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_traveler_id UUID := (SELECT auth.uid()::uuid);
  v_request_id  UUID;
  v_guide_id    UUID;
  v_price_minor INTEGER;
  v_currency    TEXT;
  v_starts_at   TIMESTAMPTZ;
  v_participants_count INTEGER;
  v_booking_id  UUID;
  v_thread_id   UUID;
BEGIN
  IF v_traveler_id IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT request_id, guide_id, price_minor, currency, starts_at
  INTO v_request_id, v_guide_id, v_price_minor, v_currency, v_starts_at
  FROM public.guide_offers
  WHERE id = p_offer_id
    AND status = 'pending';

  IF v_request_id IS NULL THEN
    RAISE EXCEPTION 'offer_not_found';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.traveler_requests
    WHERE id = v_request_id
      AND traveler_id = v_traveler_id
  ) THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT participants_count INTO v_participants_count
  FROM public.traveler_requests
  WHERE id = v_request_id;

  UPDATE public.guide_offers
  SET status = 'accepted', updated_at = NOW()
  WHERE id = p_offer_id;

  UPDATE public.guide_offers
  SET status = 'declined', updated_at = NOW()
  WHERE request_id = v_request_id
    AND id != p_offer_id
    AND status = 'pending';

  UPDATE public.traveler_requests
  SET status = 'booked', updated_at = NOW()
  WHERE id = v_request_id;

  INSERT INTO public.bookings (
    traveler_id,
    guide_id,
    request_id,
    offer_id,
    status,
    party_size,
    subtotal_minor,
    currency,
    starts_at,
    cancellation_policy_snapshot
  )
  VALUES (
    v_traveler_id,
    v_guide_id,
    v_request_id,
    p_offer_id,
    'awaiting_guide_confirmation',
    COALESCE(v_participants_count, 1),
    v_price_minor,
    COALESCE(v_currency, 'RUB'),
    v_starts_at,
    '{}'::jsonb
  )
  RETURNING id INTO v_booking_id;

  INSERT INTO public.conversation_threads (subject_type, booking_id, created_by)
  VALUES ('booking', v_booking_id, v_traveler_id)
  RETURNING id INTO v_thread_id;

  RETURN v_thread_id;
END;
$$;


ALTER FUNCTION "public"."accept_offer"("p_offer_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_set_account_status"("p_target_user_id" "uuid", "p_status" "public"."account_status", "p_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor       uuid := (select auth.uid());
  v_current     public.account_status;
  v_target_role public.app_role;
  v_reason      text := nullif(btrim(coalesce(p_reason, '')), '');
begin
  if not is_admin() then
    raise exception 'forbidden: admin role required';
  end if;

  if p_target_user_id = v_actor then
    raise exception 'forbidden: administrators cannot change their own account status';
  end if;

  select account_status, role into v_current, v_target_role
    from public.profiles where id = p_target_user_id;

  if v_current is null then
    raise exception 'not_found: target user does not exist';
  end if;

  if v_current = p_status then
    raise exception 'noop: account is already in the requested status';
  end if;

  -- Last-active-admin guard: never suspend/archive the final active admin.
  if v_target_role = 'admin' and p_status <> 'active' then
    if (
      select count(*) from public.profiles
       where role = 'admin' and account_status = 'active' and id <> p_target_user_id
    ) = 0 then
      raise exception 'forbidden: cannot suspend or archive the last active administrator';
    end if;
  end if;

  update public.profiles
     set account_status    = p_status,
         status_reason     = v_reason,
         status_changed_at = now(),
         status_changed_by = v_actor,
         updated_at        = now()
   where id = p_target_user_id;

  insert into public.admin_audit_log (actor_id, action, target_type, target_id, metadata)
  values (
    v_actor,
    'account_status.' || p_status::text,
    'user',
    p_target_user_id,
    jsonb_build_object('from', v_current::text, 'to', p_status::text, 'reason', v_reason)
  );
end;
$$;


ALTER FUNCTION "public"."admin_set_account_status"("p_target_user_id" "uuid", "p_status" "public"."account_status", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_access_booking_thread"("target_booking_id" "uuid", "target_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select coalesce(target_user_id, (select auth.uid()::uuid)) is not null
    and exists (
      select 1 from public.bookings b
      where b.id = target_booking_id
        and (
          b.traveler_id = coalesce(target_user_id, (select auth.uid()::uuid))
          or b.guide_id = coalesce(target_user_id, (select auth.uid()::uuid))
          or public.user_has_role(coalesce(target_user_id, (select auth.uid()::uuid)), 'admin'::public.app_role)
        )
    );
$$;


ALTER FUNCTION "public"."can_access_booking_thread"("target_booking_id" "uuid", "target_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_access_conversation_thread"("target_thread_id" "uuid", "target_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select coalesce(target_user_id, (select auth.uid()::uuid)) is not null
    and exists (
      select 1 from public.conversation_threads ct
      where ct.id = target_thread_id
        and (
          ct.created_by = coalesce(target_user_id, (select auth.uid()::uuid))
          or case ct.subject_type
            when 'request' then public.can_access_request_thread(ct.request_id, coalesce(target_user_id, (select auth.uid()::uuid)))
            when 'offer'   then public.can_access_offer_thread(ct.offer_id,     coalesce(target_user_id, (select auth.uid()::uuid)))
            when 'booking' then public.can_access_booking_thread(ct.booking_id, coalesce(target_user_id, (select auth.uid()::uuid)))
            when 'dispute' then public.can_access_dispute_thread(ct.dispute_id, coalesce(target_user_id, (select auth.uid()::uuid)))
            else false
          end
        )
    );
$$;


ALTER FUNCTION "public"."can_access_conversation_thread"("target_thread_id" "uuid", "target_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_access_dispute_thread"("target_dispute_id" "uuid", "target_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select coalesce(target_user_id, (select auth.uid()::uuid)) is not null
    and exists (
      select 1 from public.disputes d
      join public.bookings b on b.id = d.booking_id
      where d.id = target_dispute_id
        and (
          d.opened_by            = coalesce(target_user_id, (select auth.uid()::uuid))
          or d.assigned_admin_id = coalesce(target_user_id, (select auth.uid()::uuid))
          or b.traveler_id       = coalesce(target_user_id, (select auth.uid()::uuid))
          or b.guide_id          = coalesce(target_user_id, (select auth.uid()::uuid))
          or public.user_has_role(coalesce(target_user_id, (select auth.uid()::uuid)), 'admin'::public.app_role)
        )
    );
$$;


ALTER FUNCTION "public"."can_access_dispute_thread"("target_dispute_id" "uuid", "target_user_id" "uuid") OWNER TO "postgres";


