CREATE OR REPLACE FUNCTION "public"."clean_text_array"("input_array" "text"[]) RETURNS "text"[]
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select coalesce(
    array_agg(value order by ordinality),
    '{}'::text[]
  )
  from (
    select distinct on (value) value, ordinality
    from (
      select nullif(btrim(entry), '') as value, ordinality
      from unnest(coalesce(input_array, '{}'::text[])) with ordinality as entries(entry, ordinality)
    ) trimmed
    where value is not null
    order by value, ordinality
  ) cleaned;
$$;


ALTER FUNCTION "public"."clean_text_array"("input_array" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."count_competing_offers"("p_request_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user uuid := auth.uid();
  v_count integer;
begin
  if not public.user_has_role(v_user, 'guide'::public.app_role) then
    raise exception 'guide_required';
  end if;

  select count(*)::integer
    into v_count
  from public.guide_offers
  where request_id = p_request_id
    and status = 'pending'::public.offer_status;

  return coalesce(v_count, 0);
end;
$$;


ALTER FUNCTION "public"."count_competing_offers"("p_request_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."counter_offer"("p_offer_id" "uuid", "p_price_minor" integer, "p_message" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor_id UUID := (SELECT auth.uid()::uuid);
  v_request_id UUID;
  v_traveler_id UUID;
  v_guide_id UUID;
  v_listing_id UUID;
  v_title TEXT;
  v_currency TEXT;
  v_capacity INTEGER;
  v_starts_at TIMESTAMPTZ;
  v_ends_at TIMESTAMPTZ;
  v_inclusions TEXT[];
  v_expires_at TIMESTAMPTZ;
  v_status public.offer_status;
  v_route_stops JSONB;
  v_route_duration_minutes INTEGER;
  v_counter_offer_id UUID;
BEGIN
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  IF p_price_minor IS NULL OR p_price_minor < 0 THEN
    RAISE EXCEPTION 'invalid_price';
  END IF;

  SELECT
    go.request_id,
    tr.traveler_id,
    go.guide_id,
    go.listing_id,
    go.title,
    go.currency,
    go.capacity,
    go.starts_at,
    go.ends_at,
    go.inclusions,
    go.expires_at,
    go.status,
    go.route_stops,
    go.route_duration_minutes
  INTO
    v_request_id,
    v_traveler_id,
    v_guide_id,
    v_listing_id,
    v_title,
    v_currency,
    v_capacity,
    v_starts_at,
    v_ends_at,
    v_inclusions,
    v_expires_at,
    v_status,
    v_route_stops,
    v_route_duration_minutes
  FROM public.guide_offers go
  JOIN public.traveler_requests tr ON tr.id = go.request_id
  WHERE go.id = p_offer_id
  FOR UPDATE OF go;

  IF v_request_id IS NULL THEN
    RAISE EXCEPTION 'offer_not_found';
  END IF;

  IF v_traveler_id IS DISTINCT FROM v_actor_id THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  IF v_status IS DISTINCT FROM 'pending'::public.offer_status THEN
    RAISE EXCEPTION 'offer_not_pending';
  END IF;

  UPDATE public.guide_offers
  SET status = 'counter_offered'::public.offer_status,
      updated_at = timezone('utc', now())
  WHERE id = p_offer_id
    AND status = 'pending'::public.offer_status;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'offer_not_pending';
  END IF;

  INSERT INTO public.guide_offers (
    request_id,
    guide_id,
    listing_id,
    title,
    message,
    price_minor,
    currency,
    capacity,
    starts_at,
    ends_at,
    inclusions,
    expires_at,
    status,
    route_stops,
    route_duration_minutes
  )
  VALUES (
    v_request_id,
    v_guide_id,
    v_listing_id,
    v_title,
    NULLIF(BTRIM(p_message), ''),
    p_price_minor,
    COALESCE(v_currency, 'RUB'),
    v_capacity,
    v_starts_at,
    v_ends_at,
    COALESCE(v_inclusions, '{}'::text[]),
    v_expires_at,
    'pending'::public.offer_status,
    COALESCE(v_route_stops, '[]'::jsonb),
    v_route_duration_minutes
  )
  RETURNING id INTO v_counter_offer_id;

  RETURN v_counter_offer_id;
END;
$$;


ALTER FUNCTION "public"."counter_offer"("p_offer_id" "uuid", "p_price_minor" integer, "p_message" "text") OWNER TO "postgres";


