CREATE OR REPLACE FUNCTION "public"."custom_access_token_hook"("event" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  claims jsonb;
  user_role text;
begin
  select p.role::text
    into user_role
    from public.profiles as p
   where p.id = (event->>'user_id')::uuid;

  claims := coalesce(event->'claims', '{}'::jsonb);

  if user_role is not null then
    if jsonb_typeof(claims->'app_metadata') is distinct from 'object' then
      claims := jsonb_set(claims, '{app_metadata}', '{}'::jsonb, true);
    end if;

    claims := jsonb_set(
      claims,
      '{app_metadata,role}',
      to_jsonb(user_role),
      true
    );
  end if;

  return jsonb_set(coalesce(event, '{}'::jsonb), '{claims}', claims, true);
end;
$$;


ALTER FUNCTION "public"."custom_access_token_hook"("event" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_batch_refresh_all_ratings"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  lock_obtained boolean;
BEGIN
  -- Advisory lock prevents concurrent runs
  SELECT pg_try_advisory_lock(hashtext('fn_batch_refresh_all_ratings')) INTO lock_obtained;
  IF NOT lock_obtained THEN
    RETURN; -- Another instance is running
  END IF;

  -- Refresh listings that have new reviews in last 24h
  UPDATE public.listings l
  SET
    average_rating = COALESCE((
      SELECT AVG(r.rating)::numeric(3,2)
      FROM public.reviews r
      WHERE r.listing_id = l.id AND r.status = 'published'
    ), 0),
    review_count = COALESCE((
      SELECT COUNT(*) FROM public.reviews r
      WHERE r.listing_id = l.id AND r.status = 'published'
    ), 0)
  WHERE l.id IN (
    SELECT DISTINCT listing_id FROM public.reviews
    WHERE created_at > NOW() - INTERVAL '25 hours'
  );

  -- Refresh guide profiles for affected guides
  UPDATE public.guide_profiles gp
  SET
    average_rating = COALESCE((
      SELECT AVG(r.rating)::numeric(3,2)
      FROM public.reviews r
      WHERE r.guide_id = gp.user_id AND r.status = 'published'
    ), 0),
    review_count = COALESCE((
      SELECT COUNT(*) FROM public.reviews r
      WHERE r.guide_id = gp.user_id AND r.status = 'published'
    ), 0)
  WHERE gp.user_id IN (
    SELECT DISTINCT guide_id FROM public.reviews
    WHERE created_at > NOW() - INTERVAL '25 hours'
  );

  PERFORM pg_advisory_unlock(hashtext('fn_batch_refresh_all_ratings'));
END;
$$;


ALTER FUNCTION "public"."fn_batch_refresh_all_ratings"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_deliver_pending_notifications"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  lock_obtained boolean;
BEGIN
  SELECT pg_try_advisory_lock(hashtext('fn_deliver_pending_notifications')) INTO lock_obtained;
  IF NOT lock_obtained THEN RETURN; END IF;

  -- Mark stale pending notifications as failed (older than 1 hour)
  UPDATE public.notifications
  SET status = 'failed'
  WHERE status = 'pending'
    AND created_at < NOW() - INTERVAL '1 hour';

  -- in_app notifications are "delivered" immediately (just marked sent)
  UPDATE public.notifications
  SET status = 'sent'
  WHERE status = 'pending'
    AND channel = 'in_app';

  -- Email and telegram channels: mark for external pickup
  -- (actual sending handled by edge function or external script)
  -- Just mark as 'sent' here — external systems poll for sent+channel
  UPDATE public.notifications
  SET status = 'sent'
  WHERE status = 'pending'
    AND channel IN ('email', 'telegram')
    AND created_at > NOW() - INTERVAL '30 minutes';

  PERFORM pg_advisory_unlock(hashtext('fn_deliver_pending_notifications'));
END;
$$;


ALTER FUNCTION "public"."fn_deliver_pending_notifications"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_enforce_listing_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  old_s text := OLD.status::text;
  new_s text := NEW.status::text;
  tripster_states text[] := ARRAY['draft','pending_review','active','rejected','archived'];
BEGIN
  -- Only enforce when both are Tripster moderation states
  IF old_s = ANY(tripster_states) AND new_s = ANY(tripster_states) THEN
    IF NOT (
      (old_s = 'draft'          AND new_s = 'pending_review')              OR
      (old_s = 'pending_review' AND new_s IN ('active','rejected'))        OR
      (old_s = 'active'         AND new_s IN ('pending_review','archived')) OR
      (old_s = 'rejected'       AND new_s IN ('pending_review','archived')) OR
      (old_s = new_s)
    ) THEN
      RAISE EXCEPTION 'Illegal listing status transition: % → %.', old_s, new_s;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_enforce_listing_transition"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_enforce_offer_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  old_s text := OLD.status::text;
  new_s text := NEW.status::text;
  tripster_states text[] := ARRAY['bid_sent','confirmed','active','completed','declined'];
BEGIN
  -- Only enforce Tripster transitions when both states are in the Tripster set
  IF old_s = ANY(tripster_states) AND new_s = ANY(tripster_states) THEN
    IF NOT (
      (old_s = 'bid_sent'  AND new_s IN ('confirmed','declined')) OR
      (old_s = 'confirmed' AND new_s IN ('active','declined'))    OR
      (old_s = 'active'    AND new_s = 'completed')               OR
      (old_s = new_s) -- idempotent same-state write
    ) THEN
      RAISE EXCEPTION 'Illegal offer transition: % → %. Tripster SM violation.', old_s, new_s;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_enforce_offer_transition"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_enforce_reply_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  old_s text := OLD.status;
  new_s text := NEW.status;
BEGIN
  IF NOT (
    (old_s = 'draft'          AND new_s = 'pending_review')  OR
    (old_s = 'pending_review' AND new_s IN ('published','draft')) OR
    (old_s = new_s)
  ) THEN
    RAISE EXCEPTION 'Illegal reply transition: % → %.', old_s, new_s;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_enforce_reply_transition"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_enforce_review_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  old_s text := OLD.status::text;
  new_s text := NEW.status::text;
BEGIN
  IF NOT (
    (old_s = 'draft'     AND new_s IN ('submitted'))            OR
    (old_s = 'submitted' AND new_s IN ('published','hidden'))   OR
    (old_s = 'published' AND new_s = 'hidden')                  OR
    (old_s = new_s)
  ) THEN
    RAISE EXCEPTION 'Illegal review transition: % → %.', old_s, new_s;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_enforce_review_transition"() OWNER TO "postgres";


