CREATE OR REPLACE FUNCTION "public"."open_dispute"("p_booking_id" "uuid", "p_reason" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor_id UUID := (SELECT auth.uid()::uuid);
  v_traveler_id UUID;
  v_guide_id UUID;
  v_status public.booking_status;
  v_reason TEXT := NULLIF(BTRIM(p_reason), '');
  v_dispute_id UUID;
BEGIN
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  IF v_reason IS NULL THEN
    RAISE EXCEPTION 'invalid_dispute_reason';
  END IF;

  SELECT traveler_id, guide_id, status
  INTO v_traveler_id, v_guide_id, v_status
  FROM public.bookings
  WHERE id = p_booking_id
  FOR UPDATE;

  IF v_traveler_id IS NULL THEN
    RAISE EXCEPTION 'booking_not_found';
  END IF;

  IF v_actor_id IS DISTINCT FROM v_traveler_id
    AND v_actor_id IS DISTINCT FROM v_guide_id THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  IF v_status = 'disputed'::public.booking_status THEN
    RAISE EXCEPTION 'booking_already_disputed';
  END IF;

  IF v_status IN (
    'cancelled'::public.booking_status,
    'no_show'::public.booking_status
  ) THEN
    RAISE EXCEPTION 'booking_not_disputable';
  END IF;

  UPDATE public.bookings
  SET status = 'disputed'::public.booking_status,
      updated_at = timezone('utc', now())
  WHERE id = p_booking_id;

  INSERT INTO public.disputes (
    booking_id,
    opened_by,
    status,
    reason
  )
  VALUES (
    p_booking_id,
    v_actor_id,
    'open',
    v_reason
  )
  RETURNING id INTO v_dispute_id;

  INSERT INTO public.dispute_events (
    dispute_id,
    actor_id,
    event_type,
    payload
  )
  VALUES (
    v_dispute_id,
    v_actor_id,
    'opened',
    jsonb_build_object(
      'booking_id', p_booking_id,
      'reason', v_reason
    )
  );

  RETURN v_dispute_id;
END;
$$;


ALTER FUNCTION "public"."open_dispute"("p_booking_id" "uuid", "p_reason" "text") OWNER TO "postgres";


