CREATE OR REPLACE FUNCTION "public"."record_marketplace_event"("p_scope" "public"."event_scope", "p_request_id" "uuid" DEFAULT NULL::"uuid", "p_booking_id" "uuid" DEFAULT NULL::"uuid", "p_dispute_id" "uuid" DEFAULT NULL::"uuid", "p_event_type" "text" DEFAULT NULL::"text", "p_summary" "text" DEFAULT NULL::"text", "p_detail" "text" DEFAULT NULL::"text", "p_payload" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor_id uuid := (SELECT auth.uid()::uuid);
  v_event_id uuid;
BEGIN
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'unauthenticated';
  END IF;

  INSERT INTO public.marketplace_events (
    scope,
    request_id,
    booking_id,
    dispute_id,
    actor_id,
    event_type,
    summary,
    detail,
    payload
  )
  VALUES (
    p_scope,
    p_request_id,
    p_booking_id,
    p_dispute_id,
    v_actor_id,
    p_event_type,
    p_summary,
    p_detail,
    COALESCE(p_payload, '{}'::jsonb)
  )
  RETURNING id INTO v_event_id;

  RETURN v_event_id;
END;
$$;


