    CONSTRAINT "guide_profiles_legal_status_check" CHECK (("legal_status" = ANY (ARRAY['self_employed'::"text", 'individual'::"text", 'company'::"text"]))),
    CONSTRAINT "guide_profiles_max_group_size_check" CHECK (("max_group_size" > 0)),
    CONSTRAINT "guide_profiles_rating_check" CHECK ((("rating" >= (0)::numeric) AND ("rating" <= (5)::numeric))),
    CONSTRAINT "guide_profiles_years_experience_check" CHECK (("years_experience" >= 0)),
    CONSTRAINT "guide_specializations_valid" CHECK (("specializations" <@ ARRAY['history_culture'::"text", 'nature'::"text", 'food'::"text", 'art'::"text", 'unusual'::"text", 'night'::"text", 'active'::"text", 'water'::"text", 'religion'::"text"]))
);


