CREATE OR REPLACE FUNCTION "public"."submit_review"("p_booking_id" "uuid", "p_guide_id" "uuid", "p_listing_id" "uuid", "p_overall" integer, "p_body" "text", "p_material" integer, "p_engagement" integer, "p_knowledge" integer, "p_route" integer) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor_id UUID := (SELECT auth.uid()::uuid);
  v_traveler_id UUID;
  v_booking_guide_id UUID;
  v_booking_listing_id UUID;
  v_booking_status public.booking_status;
  v_resolved_listing_id UUID;
  v_review_id UUID;
BEGIN
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  IF p_overall NOT BETWEEN 1 AND 5
    OR p_material NOT BETWEEN 1 AND 5
    OR p_engagement NOT BETWEEN 1 AND 5
    OR p_knowledge NOT BETWEEN 1 AND 5
    OR p_route NOT BETWEEN 1 AND 5 THEN
    RAISE EXCEPTION 'invalid_review_score';
  END IF;

  SELECT traveler_id, guide_id, listing_id, status
  INTO v_traveler_id, v_booking_guide_id, v_booking_listing_id, v_booking_status
  FROM public.bookings
  WHERE id = p_booking_id
  FOR UPDATE;

  IF v_traveler_id IS NULL THEN
    RAISE EXCEPTION 'booking_not_found';
  END IF;

  IF v_traveler_id IS DISTINCT FROM v_actor_id THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  IF v_booking_status IS DISTINCT FROM 'completed'::public.booking_status THEN
    RAISE EXCEPTION 'booking_not_completed';
  END IF;

  IF v_booking_guide_id IS DISTINCT FROM p_guide_id THEN
    RAISE EXCEPTION 'guide_mismatch';
  END IF;

  IF p_listing_id IS NOT NULL
    AND v_booking_listing_id IS NOT NULL
    AND v_booking_listing_id IS DISTINCT FROM p_listing_id THEN
    RAISE EXCEPTION 'listing_mismatch';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.reviews
    WHERE booking_id = p_booking_id
  ) THEN
    RAISE EXCEPTION 'review_already_exists';
  END IF;

  v_resolved_listing_id := COALESCE(p_listing_id, v_booking_listing_id);

  INSERT INTO public.reviews (
    booking_id,
    traveler_id,
    guide_id,
    listing_id,
    rating,
    body,
    status
  )
  VALUES (
    p_booking_id,
    v_actor_id,
    p_guide_id,
    v_resolved_listing_id,
    p_overall,
    NULLIF(BTRIM(p_body), ''),
    'published'::public.review_status
  )
  RETURNING id INTO v_review_id;

  INSERT INTO public.review_ratings_breakdown (review_id, axis, score)
  VALUES
    (v_review_id, 'material', p_material::smallint),
    (v_review_id, 'engagement', p_engagement::smallint),
    (v_review_id, 'knowledge', p_knowledge::smallint),
    (v_review_id, 'route', p_route::smallint);

  RETURN v_review_id;
END;
$$;


ALTER FUNCTION "public"."submit_review"("p_booking_id" "uuid", "p_guide_id" "uuid", "p_listing_id" "uuid", "p_overall" integer, "p_body" "text", "p_material" integer, "p_engagement" integer, "p_knowledge" integer, "p_route" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_guide_profile_onboarding_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  new.bio            := nullif(btrim(new.bio), '');
  new.specialization := nullif(btrim(new.specialization), '');
  new.regions        := public.clean_text_array(new.regions);
  new.languages      := public.clean_text_array(new.languages);
  new.specialties    := public.clean_text_array(new.specialties);
  new.is_available   := coalesce(new.is_available, false);

  if new.specialization is null and coalesce(array_length(new.specialties, 1), 0) > 0 then
    new.specialization := new.specialties[1];
  elsif new.specialization is not null and coalesce(array_length(new.specialties, 1), 0) = 0 then
    new.specialties := array[new.specialization];
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."sync_guide_profile_onboarding_fields"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_refresh_rating_on_review"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.status = 'published' AND (OLD.status IS NULL OR OLD.status != 'published') THEN
    PERFORM public.fn_refresh_listing_rating(NEW.listing_id);
    PERFORM public.fn_refresh_guide_rating(NEW.guide_id);
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."tg_refresh_rating_on_review"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."touch_thread_updated_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  update public.conversation_threads
  set updated_at = timezone('utc', now())
  where id = new.thread_id;
  return new;
end;
$$;


