CREATE OR REPLACE VIEW "public"."platform_stats" AS
 SELECT ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."guide_profiles") AS "guides_active",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."listings") AS "listings_total",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."bookings") AS "trips_total";


