    "updated_at" timestamp with time zone DEFAULT "timezone"('utc'::"text", "now"()) NOT NULL,
    "bio" "text",
    "home_city" "text",
    "languages" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "birth_year" integer,
    "notification_prefs" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "telegram_chat_id" "text",
    "travel_interests" "text"[],
    "group_preference" "text",
    "phone_normalized" "text" GENERATED ALWAYS AS (NULLIF("regexp_replace"(COALESCE("phone", ''::"text"), '[^0-9]'::"text", ''::"text", 'g'::"text"), ''::"text")) STORED,
    "account_status" "public"."account_status" DEFAULT 'active'::"public"."account_status" NOT NULL,
    "status_reason" "text",
    "status_changed_at" timestamp with time zone,
    "status_changed_by" "uuid",
    CONSTRAINT "profiles_birth_year_check" CHECK ((("birth_year" >= 1900) AND ("birth_year" <= 2100)))
);


ALTER TABLE "public"."profiles" OWNER TO "postgres";


COMMENT ON COLUMN "public"."profiles"."phone_normalized" IS 'Digits-only normalisation of phone for uniqueness enforcement. Generated; do not write directly. Mirrors signUpAction normalisation.';



COMMENT ON COLUMN "public"."profiles"."account_status" IS 'Account lifecycle: active | suspended | archived. Suspended/archived users keep their data but are blocked from acting. Defaults to active.';



