CREATE TABLE IF NOT EXISTS "public"."traveler_requests" (
    "id" "uuid" DEFAULT "extensions"."gen_random_uuid"() NOT NULL,
    "traveler_id" "uuid" NOT NULL,
    "destination" "text" NOT NULL,
    "region" "text",
    "interests" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "starts_on" "date" NOT NULL,
    "ends_on" "date",
    "budget_minor" integer,
    "currency" "text" DEFAULT 'RUB'::"text" NOT NULL,
    "participants_count" integer DEFAULT 1 NOT NULL,
    "format_preference" "text",
    "notes" "text",
    "open_to_join" boolean DEFAULT false NOT NULL,
    "allow_guide_suggestions" boolean DEFAULT true NOT NULL,
    "group_capacity" integer,
    "status" "public"."request_status" DEFAULT 'open'::"public"."request_status" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "timezone"('utc'::"text", "now"()) NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "timezone"('utc'::"text", "now"()) NOT NULL,
    "start_time" time without time zone,
    "end_time" time without time zone,
    "date_flexibility" "text" DEFAULT 'exact'::"text" NOT NULL,
    "date_locked" boolean DEFAULT true NOT NULL,
    "time_locked" boolean DEFAULT true NOT NULL,
    "count_locked" boolean DEFAULT true NOT NULL,
    "budget_locked" boolean DEFAULT true NOT NULL,
    "date_window" "text" DEFAULT 'week'::"text" NOT NULL,
    "requested_languages" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "expires_at" timestamp with time zone,
    CONSTRAINT "traveler_requests_budget_minor_check" CHECK (("budget_minor" >= 0)),
    CONSTRAINT "traveler_requests_check" CHECK (("ends_on" >= "starts_on")),
    CONSTRAINT "traveler_requests_date_flexibility_check" CHECK (("date_flexibility" = ANY (ARRAY['exact'::"text", 'few_days'::"text"]))),
    CONSTRAINT "traveler_requests_date_window_check" CHECK (("date_window" = ANY (ARRAY['one_day'::"text", 'two_days'::"text", 'three_days'::"text", 'week'::"text", 'two_weeks'::"text"]))),
    CONSTRAINT "traveler_requests_group_capacity_check" CHECK (("group_capacity" > 0)),
    CONSTRAINT "traveler_requests_participants_count_check" CHECK (("participants_count" > 0))
);


ALTER TABLE "public"."traveler_requests" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_guide_dashboard_kpi" AS
 SELECT "gp"."user_id" AS "guide_id",
    "gp"."average_rating",
    "gp"."review_count",
    "gp"."response_rate",
    "count"(DISTINCT "l"."id") AS "listing_count",
    "count"(DISTINCT "b"."id") FILTER (WHERE ("b"."status" = 'confirmed'::"public"."booking_status")) AS "active_bookings",
    "count"(DISTINCT "b"."id") FILTER (WHERE ("b"."status" = 'completed'::"public"."booking_status")) AS "completed_bookings",
    "count"(DISTINCT "tr"."id") AS "open_requests"
   FROM ((("public"."guide_profiles" "gp"
     LEFT JOIN "public"."listings" "l" ON (("l"."guide_id" = "gp"."user_id")))
     LEFT JOIN "public"."bookings" "b" ON (("b"."guide_id" = "gp"."user_id")))
     LEFT JOIN "public"."traveler_requests" "tr" ON (("tr"."status" = 'open'::"public"."request_status")))
  GROUP BY "gp"."user_id", "gp"."average_rating", "gp"."review_count", "gp"."response_rate";


ALTER VIEW "public"."v_guide_dashboard_kpi" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_guide_public_profile" AS
 SELECT "gp"."user_id",
    "gp"."slug",
    "p"."full_name",
    "gp"."bio",
    "gp"."regions",
    "gp"."languages",
    "gp"."specialties",
    "gp"."average_rating",
    "gp"."review_count",
    "gp"."response_rate",
    "gp"."contact_visibility_unlocked",
    "gp"."is_available",
    "gp"."locale",
    "gp"."preferred_currency",
    "p"."avatar_url",
    "gp"."years_experience",
    ( SELECT "count"(*) AS "count"
           FROM "public"."bookings" "b"
          WHERE (("b"."guide_id" = "gp"."user_id") AND ("b"."status" = 'completed'::"public"."booking_status"))) AS "trips_completed",
    ( SELECT "round"(((100.0 * ("count"(*) FILTER (WHERE ("r"."rating" >= 4)))::numeric) / (NULLIF("count"(*), 0))::numeric)) AS "round"
           FROM "public"."reviews" "r"
          WHERE (("r"."guide_id" = "gp"."user_id") AND ("r"."status" = 'published'::"public"."review_status"))) AS "recommend_pct"
   FROM ("public"."guide_profiles" "gp"
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "gp"."user_id")))
  WHERE ("gp"."verification_status" = 'approved'::"public"."guide_verification_status");


ALTER VIEW "public"."v_guide_public_profile" OWNER TO "postgres";


