CREATE OR REPLACE VIEW "public"."v_listing_detail_excursion" AS
 SELECT "l"."id",
    "l"."title",
    "l"."description",
    "l"."exp_type",
    "l"."format",
    "l"."languages",
    "l"."average_rating",
    "l"."review_count",
    "l"."price_from_minor",
    "l"."currency",
    "l"."duration_minutes",
    "l"."meeting_point",
    "l"."included",
    "l"."not_included",
    "l"."pii_gate_rate",
    "l"."booking_cutoff_hours",
    "l"."instant_booking",
    "json_agg"(DISTINCT ("to_jsonb"("ls".*) - 'listing_id'::"text")) FILTER (WHERE ("ls"."id" IS NOT NULL)) AS "schedule",
    "json_agg"(DISTINCT ("to_jsonb"("lt".*) - 'listing_id'::"text")) FILTER (WHERE ("lt"."id" IS NOT NULL)) AS "tariffs",
    "json_agg"(DISTINCT ("to_jsonb"("lp".*) - 'listing_id'::"text")) FILTER (WHERE ("lp"."id" IS NOT NULL)) AS "photos"
   FROM ((("public"."listings" "l"
     LEFT JOIN "public"."listing_schedule" "ls" ON (("ls"."listing_id" = "l"."id")))
     LEFT JOIN "public"."listing_tariffs" "lt" ON (("lt"."listing_id" = "l"."id")))
     LEFT JOIN "public"."listing_photos" "lp" ON (("lp"."listing_id" = "l"."id")))
  GROUP BY "l"."id";



CREATE OR REPLACE VIEW "public"."v_listing_detail_tour" AS
 SELECT "l"."id",
    "l"."title",
    "l"."description",
    "l"."exp_type",
    "l"."format",
    "l"."languages",
    "l"."average_rating",
    "l"."review_count",
    "l"."price_from_minor",
    "l"."currency",
    "l"."difficulty_level",
    "l"."included",
    "l"."not_included",
    "l"."accommodation",
    "l"."pii_gate_rate",
    "l"."booking_cutoff_hours",
    "l"."instant_booking",
    "json_agg"(DISTINCT ("to_jsonb"("ld".*) - 'listing_id'::"text")) FILTER (WHERE ("ld"."listing_id" IS NOT NULL)) AS "days",
    "json_agg"(DISTINCT ("to_jsonb"("lm".*) - 'listing_id'::"text")) FILTER (WHERE ("lm"."listing_id" IS NOT NULL)) AS "meals",
    "json_agg"(DISTINCT ("to_jsonb"("ltd".*) - 'listing_id'::"text")) FILTER (WHERE ("ltd"."id" IS NOT NULL)) AS "departures",
    "json_agg"(DISTINCT ("to_jsonb"("lp".*) - 'listing_id'::"text")) FILTER (WHERE ("lp"."id" IS NOT NULL)) AS "photos"
   FROM (((("public"."listings" "l"
     LEFT JOIN "public"."listing_days" "ld" ON (("ld"."listing_id" = "l"."id")))
     LEFT JOIN "public"."listing_meals" "lm" ON (("lm"."listing_id" = "l"."id")))
     LEFT JOIN "public"."listing_tour_departures" "ltd" ON (("ltd"."listing_id" = "l"."id")))
     LEFT JOIN "public"."listing_photos" "lp" ON (("lp"."listing_id" = "l"."id")))
  GROUP BY "l"."id";



