--
-- Dumped schema changes for auth and storage
--

CREATE OR REPLACE TRIGGER "on_auth_user_created" AFTER INSERT ON "auth"."users" FOR EACH ROW EXECUTE FUNCTION "public"."handle_new_user"();



CREATE POLICY "Admins see all files" ON "storage"."objects" FOR SELECT USING (( SELECT "public"."is_admin"() AS "is_admin"));



CREATE POLICY "Private files visible to owner" ON "storage"."objects" FOR SELECT USING ((("bucket_id" = ANY (ARRAY['guide-documents'::"text", 'dispute-evidence'::"text"])) AND (("storage"."foldername"("name"))[1] = (( SELECT "auth"."uid"() AS "uid"))::"text")));



CREATE POLICY "Public buckets readable" ON "storage"."objects" FOR SELECT USING (("bucket_id" = ANY (ARRAY['guide-avatars'::"text", 'listing-media'::"text"])));



CREATE POLICY "Travelers read own avatars" ON "storage"."objects" FOR SELECT USING ((("bucket_id" = 'traveler-avatars'::"text") AND (("storage"."foldername"("name"))[1] = (( SELECT "auth"."uid"() AS "uid"))::"text")));



CREATE POLICY "Travelers update own avatars" ON "storage"."objects" FOR UPDATE USING ((("bucket_id" = 'traveler-avatars'::"text") AND (("storage"."foldername"("name"))[1] = (( SELECT "auth"."uid"() AS "uid"))::"text"))) WITH CHECK ((("bucket_id" = 'traveler-avatars'::"text") AND (("storage"."foldername"("name"))[1] = (( SELECT "auth"."uid"() AS "uid"))::"text")));



CREATE POLICY "Travelers upload own avatars" ON "storage"."objects" FOR INSERT WITH CHECK ((("bucket_id" = 'traveler-avatars'::"text") AND (("storage"."foldername"("name"))[1] = (( SELECT "auth"."uid"() AS "uid"))::"text")));



CREATE POLICY "Users upload own files" ON "storage"."objects" FOR INSERT WITH CHECK ((("bucket_id" = ANY (ARRAY['guide-avatars'::"text", 'guide-documents'::"text", 'listing-media'::"text", 'dispute-evidence'::"text"])) AND (("storage"."foldername"("name"))[1] = (( SELECT "auth"."uid"() AS "uid"))::"text")));



CREATE POLICY "dispute_evidence_insert" ON "storage"."objects" FOR INSERT WITH CHECK ((("bucket_id" = 'dispute-evidence'::"text") AND ("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid"))));



CREATE POLICY "dispute_evidence_select" ON "storage"."objects" FOR SELECT USING ((("bucket_id" = 'dispute-evidence'::"text") AND (("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid")) OR "public"."is_admin"())));



CREATE POLICY "dispute_evidence_update" ON "storage"."objects" FOR UPDATE USING ((("bucket_id" = 'dispute-evidence'::"text") AND (("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid")) OR "public"."is_admin"())));



CREATE POLICY "guide_documents_owner_delete" ON "storage"."objects" FOR DELETE USING ((("bucket_id" = 'guide-documents'::"text") AND (("storage"."foldername"("name"))[1] = (( SELECT "auth"."uid"() AS "uid"))::"text")));



CREATE POLICY "guide_media_insert" ON "storage"."objects" FOR INSERT WITH CHECK ((("bucket_id" = 'guide-media'::"text") AND ("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid"))));



CREATE POLICY "guide_media_select" ON "storage"."objects" FOR SELECT USING ((("bucket_id" = 'guide-media'::"text") AND (("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid")) OR "public"."is_admin"())));



CREATE POLICY "guide_media_update" ON "storage"."objects" FOR UPDATE USING ((("bucket_id" = 'guide-media'::"text") AND (("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid")) OR "public"."is_admin"())));



CREATE POLICY "guide_portfolio_delete" ON "storage"."objects" FOR DELETE USING ((("bucket_id" = 'guide-portfolio'::"text") AND (("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid")) OR "public"."is_admin"())));



CREATE POLICY "guide_portfolio_insert" ON "storage"."objects" FOR INSERT WITH CHECK ((("bucket_id" = 'guide-portfolio'::"text") AND ("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid"))));



CREATE POLICY "guide_portfolio_public_read" ON "storage"."objects" FOR SELECT USING (("bucket_id" = 'guide-portfolio'::"text"));



CREATE POLICY "guide_portfolio_update" ON "storage"."objects" FOR UPDATE USING ((("bucket_id" = 'guide-portfolio'::"text") AND (("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid")) OR "public"."is_admin"())));



CREATE POLICY "listing_media_insert" ON "storage"."objects" FOR INSERT WITH CHECK ((("bucket_id" = 'listing-media'::"text") AND ("split_part"("name", '/'::"text", 1) = ( SELECT ("auth"."uid"())::"text" AS "uid"))));



CREATE POLICY "listing_media_public_read" ON "storage"."objects" FOR SELECT USING (("bucket_id" = 'listing-media'::"text"));



